import * as React from 'react';
import Box from '@mui/material/Box';
import Paper from '@mui/material/Paper';

import FeaturedPost from './FeaturedPost';

import Grid from '@mui/material/Grid';


const listOfPosts = [
  {
    title: 'Featured post',
    date: 'Nov 12',
    description:
      'This is a wider card with supporting text below as a natural lead-in to additional content.',
    image: 'https://source.unsplash.com/random?wallpapers',
    imageLabel: 'Image Text',
    link: 'blog/rent',
  },
  {
    title: 'Post title',
    date: 'Nov 11',
    description:
      'This is a wider card with supporting text below as a natural lead-in to additional content.',
    image: 'https://source.unsplash.com/random?wallpapers',
    imageLabel: 'Image Text',
    link: 'blog/rent',
  },
  {
    title: 'Post title #3',
    date: 'Nov 11',
    description:
      'This is a wider card with supporting text below as a natural lead-in to additional content.',
    image: 'https://source.unsplash.com/random?wallpapers',
    imageLabel: 'Image Text',
    link: 'blog/rent',
  },
  {
    title: 'Post title #3',
    date: 'Nov 11',
    description:
      'This is a wider card with supporting text below as a natural lead-in to additional content.',
    image: 'https://source.unsplash.com/random?wallpapers',
    imageLabel: 'Image Text',
    link: 'blog/rent',
  },
];

function Blog ({ setActiveLink }) {
  return (
    <Box
      sx={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        height: '100vh',
        backgroundColor: 'grey',
      }}
    >

      {/* <Box sx={{ display: 'flex', justifyContent: 'center', width: '80%', backgroundColor: 'yellow' }}> */}

      <Grid container spacing={3} sx={{ width: '80%', marginTop: '100px' }}>
        {
          listOfPosts.map((post) => (
            <FeaturedPost
              key={post.title}
              title={post.title}
              date={post.date}
              desc={post.description}
              image={post.image}
              imageLabel={post.imageLabel}
              setActiveLink={setActiveLink}
              link={post.link}
            />
          ))
        }
      </Grid>

      {/* </Box> */}



      {/* <Paper elevation={3} gap={3}>
        {
          featuredPosts.map((post) => (
            <FeaturedPost key={post.title} post={post} />
          ))
        }
      </Paper> */}
    </Box>
  )
}

export default Blog;
